INSERT INTO experiments (title, subject, subject_area, topic, experiment_code, description, difficulty_level, simulation_type, curriculum, grade_or_form, estimated_duration, apparatus, expected_outcome, safety_precautions, teacher_notes) VALUES
('Measuring Length Using Vernier Calipers and Micrometer Screw Gauge', 'physics', 'Measurement', 'Measurement', 'PHY-G10-001', 'Measure length and diameter accurately using precision instruments and compare their accuracy.', 'Beginner', 'measure_length', 'new', 'Grade 10', 45, 'Vernier calipers, micrometer screw gauge, metre rule, various objects (ball bearing, cylinder, rod)', 'Learners understand precision measurement and the difference in accuracy between instruments.', 'Handle precision instruments gently to avoid damage. Do not force calipers or micrometer beyond their range. Clean instrument jaws after use to prevent corrosion.', 'Demonstrate proper zeroing of both instruments before taking readings. Discuss systematic and random errors. Students should record at least 3 readings and calculate the mean.'),
('Determining the Period of a Simple Pendulum', 'physics', 'Mechanics', 'Time and Motion', 'PHY-G10-002', 'Investigate the factors affecting the period of a simple pendulum.', 'Beginner', 'pendulum', 'new', 'Grade 10', 45, 'Inextensible string (various lengths), small metal bob, retort stand, stopwatch, protractor, ruler', 'Period depends on string length but not on mass or amplitude (for small angles). T = 2π√(L/g).', 'Ensure the retort stand is clamped securely to avoid toppling. Keep amplitude small (< 10°) for valid results. Keep the pendulum in the same vertical plane.', 'Have students time 10 oscillations rather than 1 to reduce timing error. Discuss how this links to SHM theory in Grade 12.'),
('Measuring Mass and Weight', 'physics', 'Measurement', 'Mass and Weight', 'PHY-G10-003', 'Distinguish between mass and weight practically using different measuring instruments.', 'Beginner', 'measure_mass', 'new', 'Grade 10', 45, 'Beam balance, spring balance (Newton meter), various objects, known masses', 'Mass is constant regardless of location; weight = mg and varies with gravitational field strength.', 'Do not overload the spring balance beyond its maximum range. Handle masses carefully to avoid dropping them on feet.', 'Compare readings from beam balance (measures mass) vs spring balance (measures weight). Emphasise g = 9.8 N/kg on Earth.'),
('Locating the Centre of Mass of an Irregular Lamina', 'physics', 'Mechanics', 'Equilibrium', 'PHY-G10-004', 'Determine the centre of gravity of an irregular flat shape using a plumb line method.', 'Intermediate', 'cog', 'new', 'Grade 10', 45, 'Irregular cardboard lamina, retort stand, pin, plumb line (thread + small mass), pencil', 'All three lines intersect at a single point — the centre of mass. The lamina balances at this point.', 'Be careful with sharp pins — use pin holder. Ensure retort stand is stable before hanging lamina.', 'Show how vehicles with a high centre of gravity are prone to toppling. Link to stability in engineering.'),
('Verification of Hooke''s Law', 'physics', 'Mechanics', 'Elasticity', 'PHY-G10-005', 'Investigate how the extension of a spring is directly proportional to the applied load.', 'Intermediate', 'hookes_law', 'new', 'Grade 10', 45, 'Steel spring, retort stand, metre rule, set of 100 g masses, pointer', 'Linear graph confirming F = kx (Hooke''s Law) up to the elastic limit.', 'Do not exceed the elastic limit of the spring. Stand clear below the spring when adding masses. Ensure retort stand is clamped firmly.', 'Students should identify where the graph becomes non-linear to locate the elastic limit. The gradient of the F vs x graph gives spring constant k.'),
('Investigating Friction on Different Surfaces', 'physics', 'Mechanics', 'Friction', 'PHY-G10-006', 'Compare frictional forces produced when a wooden block slides on rough and smooth surfaces.', 'Beginner', 'friction', 'new', 'Grade 10', 45, 'Wooden block, spring balance, rough surface board, smooth surface board, sandpaper', 'Rougher surfaces produce greater frictional forces. Friction force is independent of contact area.', 'Ensure the surface is clean and dry for valid comparisons. Pull the block slowly and steadily to maintain constant speed.', 'At constant velocity, applied force equals friction (Newton''s 1st Law). Demonstrate that friction does not depend on contact area by turning the block on its side.'),
('Principle of Moments Using a Metre Rule', 'physics', 'Moments', 'Turning Effect of Forces', 'PHY-G10-007', 'Verify the principle of moments: sum of clockwise moments = sum of anticlockwise moments.', 'Intermediate', 'moments', 'new', 'Grade 10', 45, 'Metre rule, pivot (triangular wedge), masses (100g, 200g, 500g), string loops', 'Clockwise moments equal anticlockwise moments when the system is balanced — verifying the principle of moments.', 'Clamp the pivot securely so it does not slide. Handle masses carefully when balancing.', 'Remind students that moment = Force × perpendicular distance from pivot. Use real-life examples like see-saws and spanners.'),
('Work Done and Power Calculation', 'physics', 'Energy', 'Work, Energy, Power', 'PHY-G10-008', 'Determine the work done and power output when lifting objects through a measured height.', 'Beginner', 'energy', 'new', 'Grade 10', 45, 'Known masses (0.5 kg, 1 kg), metre rule, stopwatch, pulley (optional)', 'Students can calculate work done (W = Fd = mgh) and power (P = W/t) and understand the relationship between them.', 'Do not drop masses from height. Ensure clear space below when lifting objects.', 'Emphasise that work is done only when displacement occurs in the direction of the force. Link to gravitational potential energy: GPE = mgh.'),
('Mechanical Advantage of Simple Machines', 'physics', 'Machines', 'Levers and Pulleys', 'PHY-G10-009', 'Calculate Mechanical Advantage (MA), Velocity Ratio (VR), and efficiency of simple machines.', 'Intermediate', 'machines', 'new', 'Grade 10', 45, 'Single/double pulley system, lever bar, slotted masses (load), spring balance (effort), metre rule', 'Efficiency is always < 100% due to friction losses. MA < VR for real machines.', 'Ensure pulleys are securely attached before adding loads. Do not exceed the rated load of the pulley system.', 'Show that an ideal machine would have MA = VR (100% efficiency). Friction in bearings and the weight of the string/pulley reduce efficiency.'),
('Brownian Motion Demonstration', 'physics', 'Thermal Physics', 'Kinetic Theory', 'PHY-G11-001', 'Observe random particle movement of smoke particles as evidence for the kinetic theory.', 'Intermediate', 'brownian', 'new', 'Grade 11', 45, 'Smoke cell, microscope with illuminator, smoke source, glass cover', 'Smoke particles show random, erratic (Brownian) motion due to unequal bombardment by air molecules — supporting kinetic theory.', 'Handle the smoke cell carefully — the glass can break. Avoid breathing in smoke during the demonstration. Ensure good ventilation in the laboratory.', 'Link Brownian motion to Einstein''s 1905 paper. Emphasise that the smoke particles are NOT the air molecules — they are being hit by invisible air molecules.'),
('Calibration of a Thermometer', 'physics', 'Thermal Physics', 'Thermometry', 'PHY-G11-002', 'Calibrate a liquid-in-glass thermometer by identifying and marking fixed points.', 'Intermediate', 'thermometer', 'new', 'Grade 11', 45, 'Uncalibrated thermometer tube, ice, boiling water, steam jacket, ruler, marker', 'A calibrated thermometer with accurately marked divisions between 0°C and 100°C.', 'Take extra care with boiling water and steam — severe burns risk. Hold thermometer vertically during calibration. Do not heat the sealed end of the thermometer tube.', 'Emphasise that steam is used (not boiling water surface) because steam temperature remains constant at 100°C regardless of heat intensity.'),
('Linear Expansion of Solids', 'physics', 'Thermal Physics', 'Expansion', 'PHY-G11-003', 'Demonstrate that solid materials expand when heated using the ball-and-ring apparatus.', 'Beginner', 'thermal_expansion', 'new', 'Grade 11', 45, 'Ball-and-ring apparatus (metal), Bunsen burner or heat source, safety tongs', 'Heated solids expand and cannot pass through cavities they originally fitted — confirming thermal linear expansion.', 'Use safety tongs — heated metal causes severe burns. Place hot metal on a heat-proof mat only. Do not leave Bunsen burner unattended.', 'Show real-world applications: gaps in bridges, railway expansion joints, bimetallic strips in thermostats. Discuss ΔL = αL₀ΔT.'),
('Verification of Boyle''s Law', 'physics', 'Thermal Physics', 'Pressure and Volume', 'PHY-G11-004', 'Show that pressure of a fixed mass of gas at constant temperature is inversely proportional to volume.', 'Advanced', 'pressure', 'new', 'Grade 11', 45, 'Boyle''s law apparatus, bicycle pump, pressure gauge, volume scale, oil trap', 'PV = constant at constant temperature. The P vs 1/V graph is a straight line through the origin.', 'Do not exceed the maximum pressure rating of the apparatus. Wear safety goggles — compressed gas can cause injury. Ensure all connections are tight before pumping.', 'Connect to the ideal gas equation PV = nRT. At constant T and n, PV = constant. Connect to Pressure3D simulation already in the system.'),
('Heat Transfer by Conduction', 'physics', 'Thermal Physics', 'Heat Transfer', 'PHY-G11-005', 'Compare the thermal conductivity of different metal rods by observing the rate of wax melting.', 'Beginner', 'heat_flow', 'new', 'Grade 11', 45, 'Metal rods (copper, iron, aluminium, glass), wax, heat source (Bunsen burner), retort stand', 'Copper > aluminium > iron > glass in thermal conductivity. Better conductors melt wax faster.', 'Do not touch the metal rods during heating — severe burns. Keep combustible materials away from the Bunsen burner. Use retort stand — never hold rods by hand near flame.', 'Thermal conductivity values: Cu ≈ 400, Al ≈ 235, Fe ≈ 80, Glass ≈ 1 W/mK. Link to uses in building insulation and cookware.'),
('Wave Motion on a Rope', 'physics', 'Waves', 'Wave Properties', 'PHY-G11-006', 'Generate and observe transverse wave motion to demonstrate wavelength, amplitude and frequency.', 'Beginner', 'wave_motion', 'new', 'Grade 11', 45, 'Long rope or rubber tubing, oscillator or hand, chalk, metre rule', 'Students can identify and measure wavelength, amplitude, and observe the effect of frequency on wavelength at constant speed.', 'Ensure enough space around the demonstration area. Do not use ropes near electrical equipment.', 'Use the wave equation v = fλ throughout. At constant wave speed, higher frequency → shorter wavelength. Link to sound (longitudinal) and light (transverse).'),
('Reflection of Light Using Plane Mirror', 'physics', 'Light', 'Reflection', 'PHY-G11-007', 'Verify the laws of reflection using a plane mirror, ray box, and protractor.', 'Beginner', 'light_reflection', 'new', 'Grade 11', 45, 'Plane mirror, ray box (single slit), protractor, white paper, ruler, pencil', 'Angle of incidence always equals angle of reflection (i = r) — confirming the first law of reflection.', 'Never direct ray box light directly into eyes. Handle mirror carefully — edges can be sharp.', 'Emphasise that angles are measured from the normal, not the mirror surface. Link to periscopes, kaleidoscopes, and rear-view mirrors.'),
('Refraction Through a Glass Block', 'physics', 'Light', 'Refraction', 'PHY-G11-008', 'Determine the refractive index of glass by tracing refracted rays and applying Snell''s Law.', 'Intermediate', 'light_refraction', 'new', 'Grade 11', 45, 'Rectangular glass block, optical pins (4), white paper, ruler, protractor', 'n = sin i / sin r remains constant — verifying Snell''s Law. n for glass ≈ 1.5.', 'Handle glass block with care to avoid chipping. Optical pins are sharp — handle carefully.', 'Student should calculate sin i / sin r for all three angles to verify constancy (= refractive index). Connect to optical fibres and diamonds (high refractive index).'),
('Magnetic Field Lines Around a Magnet', 'physics', 'Magnetism', 'Magnetic Fields', 'PHY-G11-009', 'Plot magnetic field patterns around a bar magnet using iron filings and a plotting compass.', 'Beginner', 'magnetic_field', 'new', 'Grade 11', 45, 'Bar magnet, iron filings, white paper, plotting compass, pencil', 'Field lines emerge from North pole, curve around, and enter South pole. Lines never cross.', 'Keep magnets away from electronic devices and watches. Do not swallow iron filings. Keep away from credit cards and magnetic storage devices.', 'Show that field strength is indicated by line density. Compare with Earth''s magnetic field. Link to compasses and navigation.'),
('Charging by Friction and Electroscope Detection', 'physics', 'Static Electricity', 'Electrostatics', 'PHY-G12-001', 'Detect and identify types of electric charge using friction and a gold-leaf electroscope.', 'Beginner', 'electrostatics', 'new', 'Grade 12', 45, 'Glass rod, ebonite rod, silk cloth, fur cloth, gold-leaf electroscope', 'Like charges repel, unlike charges attract. Electroscope detects charge — greater divergence means more charge.', 'Avoid charging in humid conditions — moisture dissipates charge. Do not use near sensitive electronic equipment. Handle glass rods carefully to prevent breakage.', 'Glass rubbed with silk becomes positive (loses electrons). Ebonite rubbed with fur becomes negative (gains electrons). Explain Coulomb''s Law qualitatively.'),
('Measuring Current and Voltage in a Circuit', 'physics', 'Electricity', 'Electrical Measurements', 'PHY-G12-002', 'Use an ammeter and voltmeter correctly in a DC circuit to measure current and voltage.', 'Beginner', 'circuit', 'new', 'Grade 12', 45, '1.5 V battery (×2), resistor (10Ω, 22Ω), connecting wires, ammeter (0–1A), voltmeter (0–5V), switch', 'Students correctly read ammeter (series) and voltmeter (parallel) readings and confirm V = IR.', 'Never connect ammeter in parallel — it will short circuit. Check polarity of meter connections before closing switch. Use only low-voltage DC batteries (6V maximum for school labs).', 'Ammeter has very low resistance (in series). Voltmeter has very high resistance (in parallel). Confirm V = IR for each set of readings.'),
('Verification of Ohm''s Law', 'physics', 'Electricity', 'Resistance', 'PHY-G12-003', 'Show that current through a metallic conductor is proportional to voltage at constant temperature.', 'Intermediate', 'ohms_law', 'new', 'Grade 12', 45, 'DC power supply (0–12V variable), ammeter, voltmeter, resistance wire (nichrome), rheostat, switch', 'I vs V graph is a straight line through the origin — confirming V ∝ I and therefore Ohm''s Law holds.', 'Do not leave current flowing for long — resistance wire heats up. Use the rheostat to control current and avoid overheating. Check connections before switching on — short circuits can damage equipment.', 'Resistance R = V/I = gradient of V vs I graph. Common non-Ohmic devices: thermistors, diodes, filament bulbs. Graph for non-Ohmic = curved.'),
('Electromagnetic Induction', 'physics', 'Electromagnetic Induction', 'Induction', 'PHY-G12-004', 'Generate an induced EMF by moving a magnet through a coil and verify Faraday''s law.', 'Advanced', 'em_induction', 'new', 'Grade 12', 45, 'Bar magnet, solenoid coil (1000 turns), galvanometer, connecting wires', 'EMF is induced only when magnetic flux is changing. Faster movement → larger deflection (greater EMF). Direction follows Lenz''s Law.', 'Avoid strong magnets near electronic devices. Keep magnets away from pacemakers and hearing aids.', 'EMF = -N × dΦ/dt (Faraday). The negative sign represents Lenz''s Law. Link to generators, transformers, and induction cooktops.'),
('Transformer Principle', 'physics', 'Electromagnetic Induction', 'Transformers', 'PHY-G12-005', 'Demonstrate step-up and step-down transformer action by comparing input and output voltages.', 'Advanced', 'transformer', 'new', 'Grade 12', 45, 'C-core or E-I iron core, primary coil (500 turns), secondary coil (interchangeable 250/1000 turns), AC power supply (6V), voltmeter ×2', 'Vs/Vp = Ns/Np — voltage ratio equals turns ratio. Step-up increases voltage; step-down decreases it.', 'Use AC supply only — transformers do not work on DC. Do not exceed rated voltage of the coils. Keep iron core experiment away from sensitive electronics.', 'Link to national grid power transmission: step-up for transmission, step-down for homes. For ideal transformer: VpIp = VsIs (power in = power out).');
